package com.tuttoposto.prayertimes.data

/**
 * Namaz tesbihatı içeriği — kaynak: herkul.app/tesbihat (her vakit için ayrı).
 *
 * Her vakit için iki sürüm: [TesbihatContent.latin] (okunuş + Türkçe açıklamalar) ve
 * [TesbihatContent.arabic] (Arapça). Açıklama/talimat metinleri (herkul'deki renkli kısımlar)
 * \u27E6 ... \u27E7 işaretleri arasına alınmıştır; ekranda farklı renkte gösterilir.
 *
 * İçerik herkul.app/tesbihat/<vakit> sayfalarından alınmıştır. Gözden geçirip düzeltebilirsiniz.
 */

/** Tesbihat paragrafı. Talimat/açıklama parçaları metinde \u27E6...\u27E7 ile işaretlidir. */
data class TesbihatPara(
    val text: String,
    val center: Boolean = false,
    val rtl: Boolean = false
)

/** Bir vakte ait tesbihat: okunuş (latin) ve Arapça sürümleri. */
data class TesbihatContent(
    val latin: List<TesbihatPara>,
    val arabic: List<TesbihatPara>
)

private fun P(text: String, center: Boolean = false, rtl: Boolean = false) =
    TesbihatPara(text, center, rtl)

